const inputData = $input.first().json.body || $input.first().json;

// 1. Verificacao de Dados Criticos
const requiredFields = ['cliente', 'servicos', 'preco_recomendado'];
let isMissingData = false;

for (const field of requiredFields) {
  if (!inputData[field]) {
    isMissingData = true;
    break;
  }
}

if (isMissingData) {
  return [{
    json: {
      status: "Sob Avaliação Técnica",
      markdown: "# Proposta Sob Avaliação Técnica\n\nFaltam dados críticos para a formulação da proposta comercial. Por favor, agende uma **Avaliação Técnica** com nosso **Tecnólogo Responsável**.",
      error: "Dados críticos ausentes (cliente, servicos ou preco_recomendado)."
    }
  }];
}

// 2. Filtro e Remocao Estrita de Custos Internos (Nao expor ao cliente)
delete inputData.custo_interno;
delete inputData.margem_lucro_interna;
delete inputData.custos_operacionais;

// 3. Regra de Gastronomia (Alta Urgencia e Fator Multiplicador)
let urgencyNotice = "";
const servicosLower = JSON.stringify(inputData.servicos).toLowerCase();
if (servicosLower.includes('chapa') || servicosLower.includes('fritadeira') || servicosLower.includes('gastronomia')) {
  // A gastronomia recebe tratamento de alta urgência com ajuste já calculado no fator multiplicador no workflow anterior.
  urgencyNotice = "\n> **Aviso de Alta Urgência:** Equipamentos de gastronomia identificados (chapas/fritadeiras). A precificação reflete o fator multiplicador de risco e a execução requer prioridade máxima devido à criticidade na operação.";
}

// 4. Tratamento de Impostos
let impostoTax = inputData.imposto_estimado_percentual || "[VALOR ESTIMADO]";

// 5. Montagem do Markdown
let markdown = `# Proposta Comercial - DL Soluções Condominiais\n\n`;
markdown += `**Cliente:** ${inputData.cliente}\n\n`;
markdown += `## Escopo dos Serviços\n`;
if (Array.isArray(inputData.servicos)) {
  inputData.servicos.forEach(s => markdown += `- ${s}\n`);
} else {
  markdown += `${inputData.servicos}\n`;
}

if (urgencyNotice) {
  markdown += `${urgencyNotice}\n\n`;
}

markdown += `## Investimento\n`;
// Mostrar APENAS faixa comercial e preco recomendado
if (inputData.faixa_comercial_min && inputData.faixa_comercial_max) {
  markdown += `- **Faixa Comercial:** R$ ${inputData.faixa_comercial_min} a R$ ${inputData.faixa_comercial_max}\n`;
} else if (inputData.preco_min && inputData.preco_max) {
  markdown += `- **Faixa Comercial:** R$ ${inputData.preco_min} a R$ ${inputData.preco_max}\n`;
}
markdown += `- **Valor Recomendado:** R$ ${inputData.preco_recomendado}\n\n`;

markdown += `### Observações Fiscais\n`;
markdown += `- **Impostos:** imposto_estimado_percentual de ${impostoTax}% (imposto estimado, sujeito a validação contábil com nosso contador).\n\n`;

markdown += `---\n\n`;
markdown += `*Nota: Esta proposta comercial não dispensa a necessidade de uma **Avaliação Técnica** in loco pelo nosso **Tecnólogo Responsável**.*\n`;
markdown += `*Operação e sistema gerenciados por **Fortress**.*`;

return [{
  json: {
    status: "Sucesso",
    markdown: markdown
  }
}];
